import os
import json
from pathlib import Path

def scan_directory(root_path="."):
    """
    Scans the directory and maps the file system architecture.
    Identifies relevant files like .env, venv, node_modules (to exclude from deep scan but mark existence).
    """
    graph = {
        "nodes": [],
        "edges": []
    }

    exclude_dirs = {".git", "node_modules", "venv", ".brain", "__pycache__", ".pytest_cache", ".vscode", "dist", "build"}

    root = Path(root_path).resolve()

    for current_path, dirs, files in os.walk(root):
        # Filter directories to avoid scanning excluded ones deeply
        # Also ignore hidden folders starting with a dot
        dirs[:] = [d for d in dirs if d not in exclude_dirs and not d.startswith(".")]

        rel_current = os.path.relpath(current_path, root)
        if rel_current == ".":
            rel_current = "root"

        graph["nodes"].append({
            "id": rel_current,
            "type": "directory",
            "path": str(current_path)
        })

        for file in files:
            file_path = Path(current_path) / file
            rel_file = os.path.relpath(file_path, root)

            graph["nodes"].append({
                "id": rel_file,
                "type": "file",
                "path": str(file_path),
                "extension": file_path.suffix
            })

            graph["edges"].append({
                "from": rel_current,
                "to": rel_file,
                "type": "contains"
            })

        # Add edges for directories (parent -> child)
        if rel_current != "root":
            parent_dir = os.path.relpath(os.path.dirname(current_path), root)
            if parent_dir == ".":
                parent_dir = "root"
            graph["edges"].append({
                "from": parent_dir,
                "to": rel_current,
                "type": "contains"
            })

    return graph

def save_graph(graph, output_file="graph.json"):
    with open(output_file, "w") as f:
        json.dump(graph, f, indent=4)
    print(f"Graph saved to {output_file}")

if __name__ == "__main__":
    project_graph = scan_directory()
    save_graph(project_graph)

import json
import os

def test_robust_json_extraction():
    # Mocking the extraction logic from src/agent.py
    def extract_json(response_text):
        start_idx = response_text.find('{')
        end_idx = response_text.rfind('}')
        if start_idx != -1 and end_idx != -1:
            json_block = response_text[start_idx:end_idx+1]
            return json.loads(json_block)
        return None

    # Case 1: Pure JSON
    res1 = '{"file.py": "print(1)"}'
    assert extract_json(res1) == {"file.py": "print(1)"}

    # Case 2: Markdown block
    res2 = 'Here is the code:\n```json\n{"file.py": "print(1)"}\n```'
    assert extract_json(res2) == {"file.py": "print(1)"}

    # Case 3: Nested braces in content
    res3 = 'Extra text {"file.py": "if True: { print(1) }" } more text'
    assert extract_json(res3) == {"file.py": "if True: { print(1) }"}

    # Case 4: No JSON
    res4 = 'Hello world'
    assert extract_json(res4) is None

    print("Robust JSON extraction tests passed!")

if __name__ == "__main__":
    test_robust_json_extraction()
